function solve(nums: number[], queries: number[][]): number[] {
    const ans: number[] = [];
    for (const [l, r, t] of queries) {
        const freq = new Map<number, number>();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            freq.set(num, (freq.get(num) || 0) + 1);
        }
        let maxFreq = -1;
        let bestNum = -1;
        for (const [num, count] of freq.entries()) {
            if (count >= t) {
                if (count > maxFreq || (count === maxFreq && num < bestNum)) {
                    maxFreq = count;
                    bestNum = num;
                }
            }
        }
        ans.push(bestNum === -1 ? -1 : bestNum);
    }
    return ans;
}
